on-merge: backport to v3.10.x","creator":{"login":"ksunden","id":2501846,"node_id":"MDQ6VXNlcjI1MDE4NDY=","avatar_url":"https://avatars.githubusercontent.com/u/2501846?v=4","gravatar_id":"","url":"https://api.github.com/users/ksunden","html_url":"https://github.com/ksunden","followers_url":"https://api.github.com/users/ksunden/followers","following_url":"https://api.github.com/users/ksunden/following{/other_user}","gists_url":"https://api.github.com/users/ksunden/gists{/gist_id}","starred_url":"https://api.github.com/users/ksunden/starred{/owner}{/repo}","subscriptions_url":"https://api.github.com/users/ksunden/subscriptions","organizations_url":"https://api.github.com/users/ksunden/orgs","repos_url":"https://api.github.com/users/ksunden/repos","events_url":"https://api.github.com/users/ksunden/events{/privacy}","received_events_url":"https://api.github.com/users/ksunden/received_events","type":"User","user_view_type":"public","site_admin":false},"open_issues":6,"closed_issues":356,"state":"open","created_at":"2023-08-09T22:35:22Z","updated_at":"2024-11-13T04:21:11Z","due_on":null,"closed_at":null},"comments":4,"created_at":"2024-11-12T13:52:50Z","updated_at":"2024-11-13T07:18:36Z","closed_at":null,"author_association":"NONE","active_lock_reason":null,"body":"### Bug summary

When trying to use TkAgg backend with tkinter compiled with tcl/tk 9.0(ex. `python-tk` with Python 3.13 from Homebrew), the backend fails to load

### Code for reproduction

```Python
from matplotlib.backends.backend_tkagg import FigureCanvasTkAgg
```


### Actual outcome

```
    from . import _tkagg
ImportError: Failed to load Tcl_SetVar
```

### Expected outcome

works as expected

### Additional information

`Tcl_SetVar` function is removed in tcl 9.0, which is used in `DpiSubclassProc` of `src/_tkagg.cpp` on Windows. The function can easily be replaced with `Tcl_SetVar2` if exists.

### Operating system

macOS 14.6

### Matplotlib Version

3.9.2

### Matplotlib Backend

_No response_

### Python version

3.13

### Jupyter version

_No response_

### Installation

pip","reactions":{"url":"https://api.github.com/repos/matplotlib/matplotlib/issues/29126/reactions","total_count":0,"+1":0,"-1":0,"laugh":0,"hooray":0,"confused":0,"heart":0,"rocket":0,"eyes":0},"timeline_url":"https://api.github.com/repos/matplotlib/matplotlib/issues/29126/timeline","performed_via_github_app":null,"state_reason":null},"comment":{"url":"https://api.github.com/repos/matplotlib/matplotlib/issues/comments/2472668598","html_url":"https://github.com/matplotlib/matplotlib/issues/29126#issuecomment-2472668598","issue_url":"https://api.github.com/repos/matplotlib/matplotlib/issues/29126","id":2472668598,"node_id":"IC_kwDOABUios6TYe22","user":{"login":"anntzer","id":1322974,"node_id":"MDQ6VXNlcjEzMjI5NzQ=","avatar_url":"https://avatars.githubusercontent.com/u/1322974?v=4","gravatar_id":"","url":"https://api.github.com/users/anntzer","html_url":"https://github.com/anntzer","followers_url":"https://api.github.com/users/anntzer/followers","following_url":"https://api.github.com/users/anntzer/following{/other_user}","gists_url":"https://api.github.com/users/anntzer/gists{/gist_id}","starred_url":"https://api.github.com/users/anntzer/starred{/owner}{/repo}","subscriptions_url":"https://api.github.com/users/anntzer/subscriptions","organizations_url":"https://api.github.com/users/anntzer/orgs","repos_url":"https://api.github.com/users/anntzer/repos","events_url":"https://api.github.com/users/anntzer/events{/privacy}","received_events_url":"https://api.github.com/users/anntzer/received_events","type":"User","user_view_type":"public","site_admin":false},"created_at":"2024-11-13T07:18:35Z","updated_at":"2024-11-13T07:18:35Z","author_association":"CONTRIBUTOR","body":"Seems reasonable enough, probably something along the lines of (totally untested)
```patch
diff --git i/src/_tkagg.cpp w/src/_tkagg.cpp
index 04ca3d4d1b..15b795d688 100644
--- i/src/_tkagg.cpp
+++ w/src/_tkagg.cpp
@@ -92,6 +92,7 @@ static Tk_PhotoPutBlock_t TK_PHOTO_PUT_BLOCK;
 // Global vars for Tcl functions.  We load these symbols from the tkinter
 // extension module or loaded Tcl libraries at run-time.
 static Tcl_SetVar_t TCL_SETVAR;
+static Tcl_SetVar2_t TCL_SETVAR2;
 
 static void
 mpl_tk_blit(py::object interp_obj, const char *photo_name,
@@ -173,7 +174,13 @@ DpiSubclassProc(HWND hwnd, UINT uMsg, WPARAM wParam, LPARAM lParam,
             std::string dpi = std::to_string(LOWORD(wParam));
 
             Tcl_Interp* interp = (Tcl_Interp*)dwRefData;
-            TCL_SETVAR(interp, var_name.c_str(), dpi.c_str(), 0);
+            if (TCL_SETVAR) {
+                TCL_SETVAR(interp, var_name.c_str(), dpi.c_str(), 0);
+            } else if (TCL_SETVAR2) {
+                TCL_SETVAR2(interp, var_name.c_str(), NULL, dpi.c_str(), 0);
+            } else {
+                // Perhaps add a failing assertion here.
+            }
         }
         return 0;
     case WM_NCDESTROY:
@@ -246,13 +253,16 @@ bool load_tcl_tk(T lib)
     if (auto ptr = dlsym(lib, "Tcl_SetVar")) {
         TCL_SETVAR = (Tcl_SetVar_t)ptr;
     }
+    if (auto ptr = dlsym(lib, "Tcl_SetVar2")) {
+        TCL_SETVAR2 = (Tcl_SetVar2_t)ptr;
+    }
     if (auto ptr = dlsym(lib, "Tk_FindPhoto")) {
         TK_FIND_PHOTO = (Tk_FindPhoto_t)ptr;
     }
     if (auto ptr = dlsym(lib, "Tk_PhotoPutBlock")) {
         TK_PHOTO_PUT_BLOCK = (Tk_PhotoPutBlock_t)ptr;
     }
-    return TCL_SETVAR && TK_FIND_PHOTO && TK_PHOTO_PUT_BLOCK;
+    return (TCL_SETVAR || TCL_SETVAR2) && TK_FIND_PHOTO && TK_PHOTO_PUT_BLOCK;
 }
 
 #ifdef WIN32_DLL
@@ -343,8 +353,8 @@ PYBIND11_MODULE(_tkagg, m, py::mod_gil_not_used())
         throw py::error_already_set();
     }
 
-    if (!TCL_SETVAR) {
-        throw py::import_error("Failed to load Tcl_SetVar");
+    if (!(TCL_SETVAR || TCL_SETVAR2)) {
+        throw py::import_error("Failed to load Tcl_SetVar and Tcl_SetVar2");
     } else if (!TK_FIND_PHOTO) {
         throw py::import_error("Failed to load Tk_FindPhoto");
     } else if (!TK_PHOTO_PUT_BLOCK) {
diff --git i/src/_tkmini.h w/src/_tkmini.h
index 85f245815e..1c74cf9720 100644
--- i/src/_tkmini.h
+++ w/src/_tkmini.h
@@ -104,6 +104,9 @@ typedef int (*Tk_PhotoPutBlock_t) (Tcl_Interp *interp, Tk_PhotoHandle handle,
 /* Tcl_SetVar typedef */
 typedef const char *(*Tcl_SetVar_t)(Tcl_Interp *interp, const char *varName,
                                     const char *newValue, int flags);
+/* Tcl_SetVar2 typedef */
+typedef const char *(*Tcl_SetVar2_t)(Tcl_Interp *interp, const char *part1, const char *part2,
+                                     const char *newValue, int flags);
 
 #ifdef __cplusplus
 }
```
